**Unit Tests for `group_by`**

```python
import pytest
from typing import Any


def group_by(items: list, key_fn) -> dict:
    result = {}
    for item in items:
        k = key_fn(item)
        result.setdefault(k, []).append(item)
    return result


# ====================== Test Data ======================


class Person:
    def __init__(self, name: str, age: int):
        self.name = name
        self.age = age


# ====================== Happy Path ======================


def test_group_by_simple_key():
    items = ["apple", "banana", "avocado", "blueberry"]
    result = group_by(items, lambda x: x[0])

    assert result == {
        "a": ["apple", "avocado"],
        "b": ["banana", "blueberry"],
    }


def test_group_by_with_objects():
    items = [
        Person("Alice", 25),
        Person("Bob", 30),
        Person("Charlie", 25),
        Person("Diana", 30),
    ]

    result = group_by(items, lambda p: p.age)

    assert len(result) == 2
    assert len(result[25]) == 2
    assert len(result[30]) == 2

    names_25 = {p.name for p in result[25]}
    names_30 = {p.name for p in result[30]}

    assert names_25 == {"Alice", "Charlie"}
    assert names_30 == {"Bob", "Diana"}


def test_group_by_with_dicts():
    items = [
        {"id": 1, "category": "fruit"},
        {"id": 2, "category": "vegetable"},
        {"id": 3, "category": "fruit"},
    ]

    result = group_by(items, lambda x: x["category"])

    assert result == {
        "fruit": [
            {"id": 1, "category": "fruit"},
            {"id": 3, "category": "fruit"},
        ],
        "vegetable": [{"id": 2, "category": "vegetable"}],
    }


def test_preserves_order_of_appearance():
    """Test that items appear in the order they were first seen."""
    items = [3, 1, 4, 1, 5, 9, 2, 6, 5, 3]
    result = group_by(items, lambda x: x % 2)

    assert result[1] == [1, 1, 5, 9, 5]  # odd numbers in order of appearance
    assert result[0] == [3, 4, 2, 6]      # even numbers in order of appearance


