def test_all_items_same_key():
    items = [10, 20, 30, 40]
    result = group_by(items, lambda x: "even")

    assert result == {"even": [10, 20, 30, 40]}


def test_key_function_returns_none():
    items = [1, 2, 3]
    result = group_by(items, lambda x: None)

    assert result == {None: [1, 2, 3]}


def test_key_function_returns_tuple():
    """Tuples are hashable and valid dictionary keys."""
    items = [(1, "a"), (2, "b"), (1, "c")]
    result = group_by(items, lambda x: (x[0], x[1] is not None))

    assert result == {
        (1, True): [(1, "a"), (1, "c")],
        (2, True): [(2, "b")],
    }


def test_key_function_returns_bool():
    items = [0, 1, False, True, None, ""]
    result = group_by(items, bool)

    assert result == {
        False: [0, False, None, ""],
        True: [1, True],
    }


